// ---------------------------------------------------------------
// Minimal HTML-escape sanitizer (esc()) -- every innerHTML write below
// runs untrusted text (question text, LLM answers) through this first.
// ---------------------------------------------------------------
function esc(s) {
  if (s == null) return '';
  return String(s).replace(/[&<>"']/g, function (c) {
    if (c === '&') return '&amp;';
    if (c === '<') return '&lt;';
    if (c === '>') return '&gt;';
    if (c === '"') return '&quot;';
    return '&#39;';
  });
}

