  let apiKey = '';
  let question = '';
  let generatedSQL = '';
  let isLoading = false;
  let lastWarnings = [];
  let lastContractsUsed = [];
  let lastExplanation = '';
  let lastSteps = [];
  let lastSource = 'none';
