  const neutral = {
    message: null,
    subMessage: null,
    ctaLabel: null,
    ctaAction: CTA_ACTIONS.NONE,
    densityLevel,
    // A pure function never dismisses — dismissal is session/UI state tracked by
    // the presenter's store, layered on top of this verdict.
    dismissed: false,
  };

