    exportSealAsJSON: typeof exportSealAsJSON !== 'undefined' ? exportSealAsJSON : null,
    CHECK_SEAL_KIND: typeof CHECK_SEAL_KIND !== 'undefined' ? CHECK_SEAL_KIND : '',
