    source,
    entityId,
    field,
    valueText: valueToText(claim.value),
    hasConfidence,
    confidenceText: hasConfidence ? `confidence ${claim.confidence}` : 'no confidence stated',
    sealedBy: claim.sealedBy == null || claim.sealedBy === '' ? null : String(claim.sealedBy),
