    const by = approvalRequest.rejection && approvalRequest.rejection.by ? approvalRequest.rejection.by : 'a party';
    const note = approvalRequest.rejection && approvalRequest.rejection.note ? ` — "${approvalRequest.rejection.note}"` : '';
